// Creates a null dev-config stub when missing (fresh clones) — the real file
// is generated by `bun dev` (scripts/dev.mjs) and is gitignored because it
// contains the local server's bearer token.
//
// SECURITY INVARIANT: this script must ONLY write a null stub to the gitignored
// path src/generated/dev-config.ts. It must NEVER write a real bearerToken, and
// the target path must stay listed in .gitignore. The real config (with the
// local token) is produced separately by the dev runner and is never committed.
import { existsSync, mkdirSync, writeFileSync } from 'node:fs';
import path from 'node:path';
const p = path.join(import.meta.dirname, '..', 'src', 'generated', 'dev-config.ts');
if (!existsSync(p)) {
  mkdirSync(path.dirname(p), { recursive: true });
  writeFileSync(p, `export interface DevConnectionConfig {
  name: string;
  androidHost: string;
  iosHost: string;
  port: number;
  bearerToken: string;
}

export const devConnectionConfig: DevConnectionConfig | null = null;
`);
  console.log('[ensure-dev-config] wrote null stub');
}
